import{_ as t,o,c as d,a2 as a}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"메뉴 관리 화면을 lego 와 동일하게 — 트리 편집·드래그 정렬·9종 권한","description":"","frontmatter":{"slug":"menu-parity","title":"메뉴 관리 화면을 lego 와 동일하게 — 트리 편집·드래그 정렬·9종 권한","authors":[],"tags":["frontend","backend","vue","vuetify","mybatis","liquibase","admin","menu","feature-015"],"created":"2026-06-07 13:05 (KST)","date":"2026-06-07T04:05:00.000Z"},"headers":[],"relativePath":"journal/2026-06-07-menu-parity.md","filePath":"journal/2026-06-07-menu-parity.md","lastUpdated":1781092690000}'),r={name:"journal/2026-06-07-menu-parity.md"};function n(s,e,c,i,l,u){return o(),d("div",null,[...e[0]||(e[0]=[a('<p>관리자 콘솔의 전체 디자인은 <a href="./2026-06-07-lego-design-port">앞서 lego 로 이식</a>했지만, <strong>메뉴 관리 기능</strong>만은 화면 구성·상호작용·권한 모델이 기준(<code>C:/ax/lego</code>)과 완전히 달랐다. Spec Kit 사이클(specify→clarify→plan→tasks→implement)로 메뉴 관리를 lego 와 동일하게 맞췄다 — <strong>백엔드 확장까지 포함하는 범위 B</strong>.</p><h2 id="무엇이-달랐나" tabindex="-1">무엇이 달랐나 <a class="header-anchor" href="#무엇이-달랐나" aria-label="Permalink to &quot;무엇이 달랐나&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>이전(004/006)</th><th>lego(기준)</th></tr></thead><tbody><tr><td>화면</td><td>1장(평면표 + 인라인 권한)</td><td><strong>2장</strong>(트리 master-detail / 권한 매트릭스)</td></tr><tr><td>트리</td><td>들여쓰기 표시만</td><td>펼침·<strong>드래그앤드롭 정렬</strong>·위/아래 이동·숨김 표시</td></tr><tr><td>메뉴 필드</td><td>name·path·icon·…</td><td>+<strong>menuCode</strong>·<strong>component</strong></td></tr><tr><td>권한</td><td>CAN_VIEW·CAN_EXEC (2)</td><td>read·create·update·delete·extra1~5 (<strong>9</strong>)</td></tr></tbody></table><h2 id="한-일" tabindex="-1">한 일 <a class="header-anchor" href="#한-일" aria-label="Permalink to &quot;한 일&quot;">​</a></h2><ul><li><strong>백엔드(feature 004 확장)</strong>: Liquibase 마이그레이션 한 벌로 <code>SYS_MENU</code> 에 <code>MENU_CODE</code>·<code>COMPONENT</code>, <code>SYS_ROLE_MENU</code> 에 9종 <code>PERM_*</code> 컬럼을 <strong>추가 + 무손실 백필</strong> (<code>PERM_READ←CAN_VIEW</code>). DTO·매퍼·서비스·컨트롤러를 9권한 모델로 전환.</li><li><strong>프론트(feature 006)</strong>: 메뉴 관리 1화면 → <strong>2화면</strong>. <code>MenuTreeNode</code>(HTML5 드래그앤드롭· 레벨 뱃지·숨김 표시) + <code>MenusView</code>(좌측 트리 / 우측 편집 패널) + <code>MenuPermissionView</code> (역할×9권한 매트릭스). 라우트·셸 네비·역할관리 &quot;권한 편집&quot; 딥링크 추가.</li></ul><h2 id="까다로웠던-지점" tabindex="-1">까다로웠던 지점 <a class="header-anchor" href="#까다로웠던-지점" aria-label="Permalink to &quot;까다로웠던 지점&quot;">​</a></h2><h3 id="_1-접근통제-기준을-바꾸면-다른-기능이-깨진다" tabindex="-1">1. 접근통제 기준을 바꾸면 다른 기능이 깨진다 <a class="header-anchor" href="#_1-접근통제-기준을-바꾸면-다른-기능이-깨진다" aria-label="Permalink to &quot;1. 접근통제 기준을 바꾸면 다른 기능이 깨진다&quot;">​</a></h3><p><code>/menus/my</code> 접근통제를 <code>CAN_VIEW=&#39;Y&#39;</code> → <code>PERM_READ=&#39;Y&#39;</code> 로 옮겼다. 그런데 <strong>권한 신청 승인</strong> 경로(<code>PermissionService</code>)는 별도 매퍼로 <code>SYS_ROLE_MENU</code> 에 <code>CAN_VIEW=&#39;Y&#39;</code> 만 넣고 있었다. 그대로 두면 승인해도 <code>PERM_READ=&#39;N&#39;</code>(기본값) 이라 메뉴가 안 보이는 회귀가 난다. 그 insert 도 <code>PERM_READ=&#39;Y&#39;</code> 를 함께 쓰도록 고쳐 막았다(SC-7: 회귀 0).</p><h3 id="_2-무손실-확장-—-컬럼은-더하기만" tabindex="-1">2. 무손실 확장 — 컬럼은 더하기만 <a class="header-anchor" href="#_2-무손실-확장-—-컬럼은-더하기만" aria-label="Permalink to &quot;2. 무손실 확장 — 컬럼은 더하기만&quot;">​</a></h3><p>기존 <code>CAN_VIEW/CAN_EXEC</code> 는 <strong>드롭하지 않고 보존</strong>했다. 신규 9컬럼을 추가하고 백필만 하면, 롤백도 addColumn 역연산으로 안전하고 기존 데이터가 손상되지 않는다. 업서트 시 보존 컬럼도 <code>PERM_READ/PERM_UPDATE</code> 와 동기화해 둘 다 일관되게 유지한다.</p><h3 id="_3-tasks-md-의-p-테스트-가-죽은-링크가-됐다" tabindex="-1">3. tasks.md 의 <code>[P](테스트)</code> 가 죽은 링크가 됐다 <a class="header-anchor" href="#_3-tasks-md-의-p-테스트-가-죽은-링크가-됐다" aria-label="Permalink to &quot;3. tasks.md 의 `[P](테스트)` 가 죽은 링크가 됐다&quot;">​</a></h3><p>산문에 <code>T010[P](테스트)</code> 라고 썼더니 VitePress strict 빌드가 <code>[P](테스트)</code> 를 마크다운 링크로 읽어 dead link 로 잡았다. 괄호를 떼어 <code>T010 (테스트, [P])</code> 로 고쳤다. 문서도 빌드 대상이라는 걸 새삼.</p><h2 id="결과" tabindex="-1">결과 <a class="header-anchor" href="#결과" aria-label="Permalink to &quot;결과&quot;">​</a></h2><ul><li>백엔드 <code>gradle :app:test</code> <strong>통과</strong>(신규 menuCode/9권한 테스트 + 회귀 0).</li><li>프론트 <code>vue-tsc + vite build</code> <strong>통과</strong>, 단위테스트 <strong>13/13</strong>.</li><li>메뉴 관리가 lego 와 동일한 2화면·트리·드래그정렬·9권한 매트릭스로 동작.</li><li>단, <strong>브라우저 픽셀 대조는 미실시</strong>(백엔드 기동 필요) — <code>npm run dev</code> 로 눈 확인 권장.</li></ul><p>규약·설계는 <code>specs/015-lego-menu-parity/</code>.</p>',15)])])}const _=t(r,[["render",n]]);export{h as __pageData,_ as default};
